// Extract message from WhatsApp webhook payload
const payload = $input.item.json.body || $input.item.json;
const entry = payload?.entry?.[0];
const change = entry?.changes?.[0]?.value;
const messages = change?.messages || [];
const contacts = change?.contacts || [];

if (!messages.length) return [];

const msg = messages[0];
if (msg.type !== 'text') return [];

const waId = msg.from;
const contact = contacts.find(c => c.wa_id === waId);

return [{
  json: {
    phone_number: '+' + waId,
    message_text: msg.text?.body || '',
    student_name: contact?.profile?.name || '',
    source_channel: 'WhatsApp',
    message_id: msg.id,
    timestamp: msg.timestamp
  }
}];

// Build Gemini prompt with IIST knowledge base
const { phone_number, message_text, student_name, source_channel } = $input.item.json;

const knowledgeBase = `
IIST Courses: B.Tech CSE (120 seats, ₹85,000/yr, JEE 85%ile), ECE (60 seats, ₹82,000/yr, JEE 70%ile), IT (60 seats, ₹82,000/yr, JEE 75%ile), ME (60 seats, ₹78,000/yr), CE (60 seats, ₹75,000/yr), MBA (60 seats, ₹65,000/yr).
Scholarships: Merit 25% off (95%ile+), SC/ST govt, Girls 10% off, Sports 20% off.
Hostel: Boys ₹45,000/yr, Girls ₹48,000/yr.
Deadline: June 30 2026. Orientation: July 15 2026.
Placement: Avg ₹6.2LPA, Highest ₹18LPA (Microsoft). 92% CSE placed.
Apply: iist.ac.in/apply | admissions@iist.ac.in | +91-731-XXXXXXX
`;

const prompt = `You are AdmitBot, IIST admission assistant. Reply in the SAME language as student (Hindi/Hinglish/English). Max 3-4 lines. 1-2 emojis. Never say 'I don't know' - redirect to counsellor.

Knowledge Base:
${knowledgeBase}

Student (${phone_number}) asks: ${message_text}

After your reply, add JSON block:
\`\`\`json
{"intent_score":"Hot|Warm|Cold","extracted_data":{"name":null,"city":null,"course_interest":null,"jee_percentile":null,"phone":null},"needs_escalation":false}
\`\`\``;

return [{ json: { ...($input.item.json), prompt } }];

// Parse Gemini response and extract reply + structured data
const rawText = $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';

const jsonMatch = rawText.match(/```json\s*([\s\S]*?)\s*```/);
let structured = {};
let replyText = rawText.trim();

if (jsonMatch) {
  try { structured = JSON.parse(jsonMatch[1]); } catch(e) {}
  replyText = rawText.substring(0, jsonMatch.index).trim();
}

const prev = $node['Extract Message'].json;

return [{
  json: {
    phone_number: prev.phone_number,
    student_name: prev.student_name || structured.extracted_data?.name || '',
    source_channel: prev.source_channel,
    message_text: prev.message_text,
    reply_text: replyText,
    intent_score: structured.intent_score || 'Cold',
    extracted_data: structured.extracted_data || {},
    needs_escalation: structured.needs_escalation || false
  }
}];
